urlset:
{% for url in urlset %}  
    {{ url.location }}
    {% if url.lastmod %}{{ url.lastmod|date:"Y-m-d" }}{% endif %}

      {{ url.item.poster.url }}
      {{ url.item.title }}
      {{ url.item.description|truncatechars:200 }}
      {{ url.location }}
      {% if url.item.year %}{{ url.item.year }}-01-01{% endif %}


{% endfor %}
